export const buildAuth = (db) => betterAuth({
    database: prismaAdapter(db),
    createSession: async (data) => {
        const token = signSessionToken(data);
        const session = await db.session.create({ data: { ...data, token } });
        await auditLog.record('session.created', { sessionId: session.id });
        return session;
    },
});
